import React, { useEffect, useState, useCallback } from "react";
import Dashboard from "./Dashboard";
import AddTask from "./AddTask";
import { useToast } from "../context/toastContext";

export default function TaskList() {
  const [tasks, setTasks] = useState([]);
  const [showAddModal, setShowAddModal] = useState(false);
  const [deleteId, setDeleteId] = useState(null);

  const { addToast } = useToast();

  const fetchAll = useCallback(async () => {
    try {
      const t = await fetch("http://localhost:8086/tasks").then(r => r.json());
      setTasks(t);
    } catch {
      addToast("Failed to load tasks", "error");
    }
  }, [addToast]);

  useEffect(() => {
    fetchAll();
  }, [fetchAll]);

  const completeTask = async (id) => {
    try {
      await fetch(`http://localhost:8086/tasks/${id}/complete`, {
        method: "PUT",
      });

      setTasks(prev =>
        prev.map(t =>
          t.id === id ? { ...t, completed: true } : t
        )
      );

      addToast("Task completed!", "success");
    } catch {
      addToast("Failed to complete task", "error");
    }
  };

  const deleteTask = async () => {
    try {
      await fetch(`http://localhost:8086/tasks/${deleteId}`, {
        method: "DELETE",
      });

      setTasks(prev => prev.filter(t => t.id !== deleteId));
      setDeleteId(null);

      addToast("Task deleted", "delete");
    } catch {
      addToast("Delete failed", "error");
    }
  };

  return (
    <div className="min-h-screen p-6 bg-gradient-to-br from-indigo-100 to-purple-200">

      <Dashboard />

      <button
        onClick={() => setShowAddModal(true)}
        className="bg-purple-600 text-white px-5 py-2 rounded-xl"
      >
        + Add Task
      </button>

      {/* TASKS */}
      <div className="grid md:grid-cols-3 gap-5 mt-6">
        {tasks.map(t => (
          <div key={t.id} className="bg-white/70 p-4 rounded-xl shadow">

            <h3 className="font-semibold">{t.title}</h3>

            <div className="flex gap-2 mt-3">
              {!t.completed && (
                <button
                  onClick={() => completeTask(t.id)}
                  className="text-green-600"
                >
                  Complete
                </button>
              )}

              <button
                onClick={() => setDeleteId(t.id)}
                className="text-red-500"
              >
                Delete
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* MODALS */}
      {showAddModal && (
        <AddTask
          closeModal={() => setShowAddModal(false)}
          onTaskAdded={() => {
            addToast("Task added successfully", "add");
            setShowAddModal(false);
            fetchAll();
          }}
        />
      )}

      {deleteId && (
        <div className="fixed inset-0 bg-black/40 flex items-center justify-center">
          <div className="bg-white p-5 rounded-xl">
            <p>Delete task?</p>

            <button onClick={deleteTask} className="text-red-500">
              Yes Delete
            </button>

            <button onClick={() => setDeleteId(null)}>
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
